import styled from 'styled-components'

import { Body } from '../typography'

const Wrapper = styled.div`
  display: flex;
  align-items: center;
  justify-content: flex-start;
`

const StyledBody = styled(Body)(
  ({ theme: { color } }) => `
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: ${color.reviewText};
`
)

type ReviewProps = {
  rating?: number
}

const getReview = (rating?: number) => {
  if (!rating) {
    return 'No reviews yet'
  }

  let reviewText = 'Very poor'

  if (rating >= 2 && rating < 4) {
    reviewText = 'Adequate'
  } else if (rating >= 4 && rating < 5) {
    reviewText = 'Very good'
  } else if (rating >= 5) {
    reviewText = 'Excellent'
  }

  return `★ ${rating.toFixed(1)} ${reviewText}`
}

export const Review = ({ rating }: ReviewProps) => (
  <Wrapper>
    <StyledBody size="S" type="span" className="review-text">
      {getReview(rating)}
    </StyledBody>
  </Wrapper>
)

import { useRef, useEffect } from 'react'
import * as React from 'react'
import { createPortal } from 'react-dom'

type Props = {
  selector: string
}

export const Portal: React.FC<React.PropsWithChildren<Props>> = ({ children, selector }) => {
  const ref = useRef<Element | null>(null)

  useEffect(() => {
    const element = document.querySelector<Element>(selector)
    if (element) {
      ref.current = element
    }
  }, [selector])

  return ref.current ? createPortal(children, ref.current) : null
}

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { Portal } from '../Portal'
import { useKey } from '../../hooks/useKeyboard'
import { Button } from '../Button'
import { useLockBodyScroll } from '../../hooks/useBodyScrollLock'

import { ModalContent, TopBar, Backdrop } from './Modal.styles'

type ModalProps = {
  isOpen: boolean
  onClose: () => void
}

export const Modal: React.FC<React.PropsWithChildren<ModalProps>> = ({
  children,
  isOpen,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <Portal selector="#modal">
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="modal"
        unmountOnExit
        nodeRef={contentRef}
      >
        <ModalContent data-testid="modal" ref={contentRef}>
          <TopBar>
            <Button
              data-testid="modal-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              aria-label="close modal"
              iconSize={16}
            />
          </TopBar>
          {children}
        </ModalContent>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="modal-backdrop" ref={backdropRef} onClick={onClose} />
      </CSSTransition>
    </Portal>
  )
}

