  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /order now/i })
    await expect(button).toBeVisible()
    await expect(button).not.toBeDisabled()
  },
}

export const Clear: Story = {
  args: {
    clear: true,
    children: 'View all restaurants',
  },
