    96→  clear = false,
    97→  round = false,
    98→  icon,
    99→  iconSize,
   100→  ...properties
   101→}: ButtonProperties) => {
   102→  const { color } = useTheme()
   103→
   104→  return (
   105→    <StyledButton
   106→      type="button"
   107→      $large={large}
